"""Add 132 extra facts to reach exactly 470. Need ~29 easy, ~61 medium, ~42 hard."""

def write_fact(f, level, tru, tkz, pru, pkz, oru, okz, corr, eru, ekz):
    f.write("    (\n")
    f.write(f'        "{level}",\n')
    f.write(f'        "{tru}", "{tkz}",\n')
    f.write(f'        "{pru}",\n')
    f.write(f'        "{pkz}",\n')
    f.write(f'        {oru},\n')
    f.write(f'        {okz},\n')
    f.write(f'        {corr},\n')
    f.write(f'        "{eru}",\n')
    f.write(f'        "{ekz}"\n')
    f.write("    ),\n")

